   1→import { RecordId, type Surreal } from "surrealdb";
   2→import type { EvidenceVerificationSummary, GovernanceFeedAction, GovernanceFeedItem } from "../../shared/contracts";
   3→
   4→// --- Shared types ---
   5→
   6→type WorkspaceQueryInput = {
   7→  surreal: Surreal;
   8→  workspaceRecord: RecordId<"workspace", string>;
   9→  limit: number;
  10→};
  11→
  12→type ProjectRow = { id: RecordId<"project", string>; name: string };
  13→
  14→// --- Internal helpers ---
  15→
  16→function toRecordIdString(record: RecordId<string, string>): string {
  17→  return record.id as string;
  18→}
  19→
  20→function toIso(value: string | Date): string {
  21→  return value instanceof Date ? value.toISOString() : new Date(value).toISOString();
  22→}
  23→
  24→async function getWorkspaceProjectRows(
  25→  surreal: Surreal,
  26→  workspaceRecord: RecordId<"workspace", string>,
  27→): Promise<ProjectRow[]> {
  28→  const [rows] = await surreal
  29→    .query<[ProjectRow[]]>(
  30→      "SELECT id, name FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
  31→      { workspace: workspaceRecord },
  32→    )
  33→    .collect<[ProjectRow[]]>();
  34→
  35→  return rows;
  36→}
  37→
  38→const WORKSPACE_SCOPE_CLAUSE = "workspace = $workspace";
  39→
  40→// --- Project context (shared setup for project-scoped queries) ---
  41→
  42→type ProjectContext = {
  43→  projectRecords: RecordId<"project", string>[];
  44→  projectNameById: Map<string, string>;
  45→};
  46→
  47→async function loadProjectContext(
  48→  surreal: Surreal,
  49→  workspaceRecord: RecordId<"workspace", string>,
  50→): Promise<ProjectContext> {
  51→  const projects = await getWorkspaceProjectRows(surreal, workspaceRecord);
  52→  return {
  53→    projectRecords: projects.map((p) => p.id),
  54→    projectNameById: new Map(projects.map((p) => [toRecordIdString(p.id), p.name])),
  55→  };
  56→}
  57→
  58→async function resolveProjectName(
  59→  surreal: Surreal,
  60→  entityRecord: RecordId<string, string>,
  61→  ctx: ProjectContext,
  62→  relation: "belongs_to" | "has_feature" = "belongs_to",
  63→): Promise<string | undefined> {
  64→  if (relation === "has_feature") {
  65→    const [projRows] = await surreal
  66→      .query<[Array<RecordId<"project", string>>]>(
  67→        "SELECT VALUE `in` FROM has_feature WHERE out = $entity AND `in` IN $projects LIMIT 1;",
  68→        { entity: entityRecord, projects: ctx.projectRecords },
  69→      )
  70→      .collect<[Array<RecordId<"project", string>>]>();
  71→    return projRows[0] ? ctx.projectNameById.get(toRecordIdString(projRows[0])) : undefined;
  72→  }
  73→
  74→  const [projRows] = await surreal
  75→    .query<[Array<RecordId<"project", string>>]>(
  76→      "SELECT VALUE out FROM belongs_to WHERE `in` = $entity AND out IN $projects LIMIT 1;",
  77→      { entity: entityRecord, projects: ctx.projectRecords },
  78→    )
  79→    .collect<[Array<RecordId<"project", string>>]>();
  80→  return projRows[0] ? ctx.projectNameById.get(toRecordIdString(projRows[0])) : undefined;
  81→}
  82→
  83→// --- Blocking tier ---
  84→
  85→export type ProvisionalDecisionRow = {
  86→  id: RecordId<"decision", string>;
  87→  summary: string;
  88→  status: string;
  89→  priority?: string;
  90→  category?: string;
  91→  created_at: string | Date;
  92→  project?: string; // resolved after query
  93→};
  94→
  95→export async function listProvisionalDecisions(
  96→  input: WorkspaceQueryInput,
  97→): Promise<ProvisionalDecisionRow[]> {
  98→  const ctx = await loadProjectContext(input.surreal, input.workspaceRecord);
  99→
 100→  const [rows] = await input.surreal
 101→    .query<[
 102→      Array<{
 103→        id: RecordId<"decision", string>;
 104→        summary: string;
 105→        status: string;
 106→        priority?: string;
 107→        category?: string;
 108→        created_at: string | Date;
 109→      }>,
 110→    ]>(
 111→      [
 112→        "SELECT id, summary, status, priority, category, created_at",
 113→        "FROM decision",
 114→        "WHERE status IN ['provisional', 'proposed', 'extracted']",
 115→        `AND ${WORKSPACE_SCOPE_CLAUSE}`,
 116→        "ORDER BY created_at DESC",
 117→        "LIMIT $limit;",
 118→      ].join(" "),
 119→      {
 120→        workspace: input.workspaceRecord,
 121→        projects: ctx.projectRecords,
 122→        limit: input.limit,
 123→      },
 124→    )
 125→    .collect<[
 126→      Array<{
 127→        id: RecordId<"decision", string>;
 128→        summary: string;
 129→        status: string;
 130→        priority?: string;
 131→        category?: string;
 132→        created_at: string | Date;
 133→      }>,
 134→    ]>();
 135→
 136→  const results: ProvisionalDecisionRow[] = [];
 137→
 138→  for (const row of rows) {
 139→    const project = await resolveProjectName(input.surreal, row.id, ctx);
 140→    results.push({
 141→      id: row.id,
 142→      summary: row.summary,
 143→      status: row.status,
 144→      ...(row.priority ? { priority: row.priority } : {}),
 145→      ...(row.category ? { category: row.category } : {}),
 146→      created_at: row.created_at,
 147→      ...(project ? { project } : {}),
 148→    });
 149→  }
 150→
 151→  return results;
 152→}
 153→
 154→export type ConflictRow = {
 155→  edgeId: string;
 156→  fromRecord: RecordId<"decision" | "feature", string>;
 157→  fromName: string;
 158→  fromKind: "decision" | "feature";
 159→  toRecord: RecordId<"decision" | "feature", string>;
 160→  toName: string;
 161→  toKind: "decision" | "feature";
 162→  description?: string;
 163→  severity?: string;
 164→  detectedAt: string;
 165→};
 166→
 167→export async function listWorkspaceConflicts(input: WorkspaceQueryInput): Promise<ConflictRow[]> {
 168→  const [rows] = await input.surreal
 169→    .query<[
 170→      Array<{
 171→        id: RecordId<"conflicts_with", string>;
 172→        in: RecordId<"decision" | "feature", string>;
 173→        out: RecordId<"decision" | "feature", string>;
 174→        description?: string;
 175→        severity?: string;
 176→        detected_at?: string | Date;
 177→      }>,
 178→    ]>(
 179→      [
 180→        "SELECT id, `in`, out, description, severity, detected_at",
 181→        "FROM conflicts_with",
 182→        "WHERE `in` IN (SELECT VALUE id FROM decision WHERE workspace = $workspace)",
 183→        "OR `in` IN (SELECT VALUE id FROM feature WHERE workspace = $workspace)",
 184→        "OR out IN (SELECT VALUE id FROM decision WHERE workspace = $workspace)",
 185→        "OR out IN (SELECT VALUE id FROM feature WHERE workspace = $workspace)",
 186→        "ORDER BY detected_at DESC",
 187→        "LIMIT $limit;",
 188→      ].join(" "),
 189→      { workspace: input.workspaceRecord, limit: input.limit },
 190→    )
 191→    .collect<[
 192→      Array<{
 193→        id: RecordId<"conflicts_with", string>;
 194→        in: RecordId<"decision" | "feature", string>;
 195→        out: RecordId<"decision" | "feature", string>;
 196→        description?: string;
 197→        severity?: string;
 198→        detected_at?: string | Date;
 199→      }>,
 200→    ]>();
 201→
 202→  const results: ConflictRow[] = [];
 203→
 204→  for (const row of rows) {
 205→    const fromKind = row.in.table.name as "decision" | "feature";
 206→    const toKind = row.out.table.name as "decision" | "feature";
 207→
 208→    const fromName = await readEntityNameByTable(input.surreal, row.in, fromKind);
 209→    const toName = await readEntityNameByTable(input.surreal, row.out, toKind);
 210→
 211→    if (!fromName || !toName) continue;
 212→
 213→    results.push({
 214→      edgeId: toRecordIdString(row.id),
 215→      fromRecord: row.in,
 216→      fromName,
 217→      fromKind,
 218→      toRecord: row.out,
 219→      toName,
 220→      toKind,
 221→      ...(row.description ? { description: row.description } : {}),
 222→      ...(row.severity ? { severity: row.severity } : {}),
 223→      detectedAt: row.detected_at ? toIso(row.detected_at) : new Date().toISOString(),
 224→    });
 225→  }
 226→
 227→  return results;
 228→}
 229→
 230→export type BlockingQuestionRow = {
 231→  id: RecordId<"question", string>;
 232→  text: string;
 233→  status: string;
 234→  priority: string;
 235→  category?: string;
 236→  created_at: string | Date;
 237→  project?: string;
 238→};
 239→
 240→export async function listBlockingQuestions(
 241→  input: WorkspaceQueryInput,
 242→): Promise<BlockingQuestionRow[]> {
 243→  const ctx = await loadProjectContext(input.surreal, input.workspaceRecord);
 244→
 245→  const [rows] = await input.surreal
 246→    .query<[
 247→      Array<{
 248→        id: RecordId<"question", string>;
 249→        text: string;
 250→        status: string;
 251→        priority: string;
 252→        category?: string;
 253→        created_at: string | Date;
 254→      }>,
