 275→        status: string;
 276→        priority: string;
 277→        category?: string;
 278→        created_at: string | Date;
 279→      }>,
 280→    ]>();
 281→
 282→  const results: BlockingQuestionRow[] = [];
 283→
 284→  for (const row of rows) {
 285→    const project = await resolveProjectName(input.surreal, row.id, ctx);
 286→    results.push({
 287→      id: row.id,
 288→      text: row.text,
 289→      status: row.status,
 290→      priority: row.priority,
 291→      ...(row.category ? { category: row.category } : {}),
 292→      created_at: row.created_at,
 293→      ...(project ? { project } : {}),
 294→    });
 295→  }
 296→
 297→  return results;
 298→}
 299→
 300→// --- Review tier ---
 301→
 302→export type LowConfidenceDecisionRow = {
 303→  id: RecordId<"decision", string>;
 304→  summary: string;
 305→  status: string;
 306→  extraction_confidence: number;
 307→  category?: string;
