 313→export async function listLowConfidenceDecisions(
 314→  input: WorkspaceQueryInput & { confidenceThreshold: number },
 315→): Promise<LowConfidenceDecisionRow[]> {
 316→  const ctx = await loadProjectContext(input.surreal, input.workspaceRecord);
 317→
 318→  const [rows] = await input.surreal
 319→    .query<[
 320→      Array<{
