 353→        category?: string;
 354→        priority?: string;
 355→        created_at: string | Date;
 356→      }>,
 357→    ]>();
 358→
 359→  const results: LowConfidenceDecisionRow[] = [];
 360→
 361→  for (const row of rows) {
