 458→export async function listStaleTasks(
 459→  input: WorkspaceQueryInput & { staleDays: number },
 460→): Promise<StaleTaskRow[]> {
 461→  const ctx = await loadProjectContext(input.surreal, input.workspaceRecord);
 462→  const cutoff = new Date(Date.now() - input.staleDays * 24 * 60 * 60 * 1000);
 463→
 464→  const [rows] = await input.surreal
 465→    .query<[
 466→      Array<{
 467→        id: RecordId<"task", string>;
 468→        title: string;
 469→        status: string;
 470→        priority?: string;
 471→        category?: string;
 472→        created_at: string | Date;
