 474→      }>,
 475→    ]>(
 476→      [
 477→        "SELECT id, title, status, priority, category, created_at, updated_at",
 478→        "FROM task",
 479→        "WHERE status NOT IN ['done', 'completed', 'blocked']",
 480→        "AND created_at < $cutoff",
 481→        `AND ${WORKSPACE_SCOPE_CLAUSE}`,
 482→        "ORDER BY created_at ASC",
 483→        "LIMIT $limit;",
 484→      ].join(" "),
 485→      {
 486→        workspace: input.workspaceRecord,
 487→        projects: ctx.projectRecords,
 488→        cutoff,
 489→        limit: input.limit,
 490→      },
 491→    )
 492→    .collect<[
 493→      Array<{
 494→        id: RecordId<"task", string>;
 495→        title: string;
 496→        status: string;
 497→        priority?: string;
 498→        category?: string;
 499→        created_at: string | Date;
 500→        updated_at?: string | Date;
 501→      }>,
 502→    ]>();
 503→
 504→  const results: StaleTaskRow[] = [];
 505→
 506→  for (const row of rows) {
 507→    const project = await resolveProjectName(input.surreal, row.id, ctx);
 508→    results.push({
 509→      id: row.id,
 510→      title: row.title,
 511→      status: row.status,
 512→      ...(row.priority ? { priority: row.priority } : {}),
 513→      ...(row.category ? { category: row.category } : {}),
 514→      created_at: row.created_at,
 515→      ...(row.updated_at ? { updated_at: row.updated_at } : {}),
 516→      ...(project ? { project } : {}),
 517→    });
 518→  }
 519→
 520→  return results;
 521→}
