 533→export async function listRecentlyCompletedItems(
 534→  input: WorkspaceQueryInput & { recentDays: number },
 535→): Promise<RecentlyCompletedRow[]> {
 536→  const ctx = await loadProjectContext(input.surreal, input.workspaceRecord);
 537→  const cutoff = new Date(Date.now() - input.recentDays * 24 * 60 * 60 * 1000);
 538→
 539→  // Completed tasks
 540→  const [taskRows] = await input.surreal
 541→    .query<[
 542→      Array<{
 543→        id: RecordId<"task", string>;
 544→        title: string;
 545→        status: string;
 546→        category?: string;
 547→        updated_at: string | Date;
 548→      }>,
 549→    ]>(
 550→      [
 551→        "SELECT id, title, status, category, updated_at",
 552→        "FROM task",
 553→        "WHERE status IN ['done', 'completed']",
 554→        "AND updated_at != NONE AND updated_at > $cutoff",
 555→        `AND ${WORKSPACE_SCOPE_CLAUSE}`,
 556→        "ORDER BY updated_at DESC",
 557→        "LIMIT $limit;",
 558→      ].join(" "),
 559→      {
 560→        workspace: input.workspaceRecord,
 561→        projects: ctx.projectRecords,
 562→        cutoff,
 563→        limit: input.limit,
 564→      },
 565→    )
 566→    .collect<[
 567→      Array<{
 568→        id: RecordId<"task", string>;
 569→        title: string;
 570→        status: string;
 571→        category?: string;
 572→        updated_at: string | Date;
 573→      }>,
 574→    ]>();
 575→
 576→  // Completed features
 577→  const [featureRows] = await input.surreal
 578→    .query<[
 579→      Array<{
 580→        id: RecordId<"feature", string>;
 581→        name: string;
 582→        status: string;
 583→        category?: string;
 584→        updated_at: string | Date;
 585→      }>,
 586→    ]>(
 587→      [
 588→        "SELECT id, name, status, updated_at",
 589→        "FROM feature",
 590→        "WHERE status = 'done'",
 591→        "AND updated_at != NONE AND updated_at > $cutoff",
 592→        "AND id IN (",
 593→        "  SELECT VALUE out FROM has_feature",
 594→        "  WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
 595→        ")",
 596→        "ORDER BY updated_at DESC",
 597→        "LIMIT $limit;",
 598→      ].join(" "),
 599→      {
 600→        workspace: input.workspaceRecord,
 601→        cutoff,
 602→        limit: input.limit,
 603→      },
 604→    )
 605→    .collect<[
 606→      Array<{
 607→        id: RecordId<"feature", string>;
 608→        name: string;
 609→        status: string;
 610→        category?: string;
 611→        updated_at: string | Date;
 612→      }>,
 613→    ]>();
 614→
 615→  const results: RecentlyCompletedRow[] = [];
 616→
 617→  for (const row of taskRows) {
 618→    const project = await resolveProjectName(input.surreal, row.id, ctx);
 619→    results.push({
 620→      id: row.id,
 621→      kind: "task",
 622→      name: row.title,
 623→      status: row.status,
 624→      ...(row.category ? { category: row.category } : {}),
 625→      updated_at: row.updated_at,
 626→      ...(project ? { project } : {}),
 627→    });
 628→  }
 629→
 630→  for (const row of featureRows) {
 631→    const project = await resolveProjectName(input.surreal, row.id, ctx, "has_feature");
 632→    results.push({
 633→      id: row.id,
 634→      kind: "feature",
 635→      name: row.name,
 636→      status: row.status,
 637→      ...(row.category ? { category: row.category } : {}),
 638→      updated_at: row.updated_at,
 639→      ...(project ? { project } : {}),
 640→    });
 641→  }
 642→
 643→  // Sort by updated_at descending
 644→  results.sort((a, b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime());
 645→
 646→  return results.slice(0, input.limit);
 647→}
