  3→import { jsonError, jsonResponse } from "../http/response";
  4→import type { ServerDependencies } from "../runtime/types";
  5→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
  6→import {
  7→  getEntityDetail,
